import { index, jsonb, pgTable, text, timestamp, uuid } from "drizzle-orm/pg-core";

export const organizationRoles = pgTable(
  "organization_roles",
  {
    id: uuid("id").primaryKey().defaultRandom(),
    organizationId: text("organization_id").notNull(),
    key: text("key").notNull(),
    name: text("name").notNull(),
    description: text("description"),
    permissions: jsonb("permissions").$type<string[]>().notNull().default([]),
    metadata: jsonb("metadata").$type<Record<string, unknown>>().notNull().default({}),
    createdAt: timestamp("created_at", { withTimezone: true }).defaultNow().notNull(),
    updatedAt: timestamp("updated_at", { withTimezone: true }).defaultNow().notNull(),
  },
  (role) => [
    index("organization_roles_organization_idx").on(role.organizationId),
    index("organization_roles_key_idx").on(role.key),
  ],
);

export type OrganizationPermission =
  | "workspace:read"
  | "workspace:update"
  | "members:invite"
  | "members:manage"
  | "billing:manage"
  | "security:manage";

export type OrganizationRole = {
  key: string;
  name: string;
  permissions: OrganizationPermission[];
};

export const defaultOrganizationRoles: OrganizationRole[] = [
  {
    key: "owner",
    name: "Owner",
    permissions: [
      "workspace:read",
      "workspace:update",
      "members:invite",
      "members:manage",
      "billing:manage",
      "security:manage",
    ],
  },
  {
    key: "admin",
    name: "Admin",
    permissions: ["workspace:read", "workspace:update", "members:invite", "members:manage"],
  },
  {
    key: "member",
    name: "Member",
    permissions: ["workspace:read"],
  },
];

export function roleHasPermission(role: OrganizationRole, permission: OrganizationPermission) {
  return role.permissions.includes(permission);
}

import { defaultOrganizationRoles } from "@/lib/stackfoundry/orgs-rbac";

export default function WorkspaceRolesPage() {
  return (
    <main className="flex flex-col gap-6 p-6">
      <div>
        <h1 className="text-2xl font-semibold">Workspace Roles</h1>
        <p className="text-muted-foreground">
          Review organization roles and the permissions they grant inside this workspace.
        </p>
      </div>
      <div className="grid gap-3">
        {defaultOrganizationRoles.map((role) => (
          <section key={role.key} className="rounded-lg border p-4">
            <h2 className="font-medium">{role.name}</h2>
            <p className="mt-2 text-sm text-muted-foreground">
              {role.permissions.length} permissions
            </p>
          </section>
        ))}
      </div>
    </main>
  );
}
